// ── RA-826: Keyword filter + deduplication ───────────────────────────────────
// Reads all RSS items, skips anything seen on previous runs (via static data),
// applies keyword filter, and outputs a single aggregated item for downstream nodes.

const staticData = this.getWorkflowStaticData('global');
const lastRunIso = staticData.lastRunAt || null;
const lastRunMs  = lastRunIso ? new Date(lastRunIso).getTime() : 0;

const KEYWORDS = [
  'gemini', 'mcp', 'model context protocol', 'scheduled action',
  'notebooklm', 'ai agent', 'automation', 'vertex ai', 'workspace ai',
  'google ai', 'google one ai',
];

const items = $input.all();
const filtered = [];

for (const item of items) {
  const pub    = item.json.isoDate || item.json.pubDate || '';
  const pubMs  = pub ? new Date(pub).getTime() : 0;

  // Skip items published before or at our last run (dedup)
  if (lastRunMs > 0 && pubMs <= lastRunMs) continue;

  const titleText   = (item.json.title || '').toLowerCase();
  const snippetText = (item.json.contentSnippet || item.json.content || '').toLowerCase();
  const fullText    = titleText + ' ' + snippetText;

  const matched = KEYWORDS.filter(kw => fullText.includes(kw));
  if (matched.length === 0) continue;

  filtered.push({
    title:     item.json.title || '',
    link:      item.json.link  || '',
    published: pub,
    summary:   (item.json.contentSnippet || '').slice(0, 600),
    keywords:  matched,
  });
}

// Advance the watermark to the most-recent item's pubDate (or now if items found)
if (filtered.length > 0 || items.length > 0) {
  const newestMs = items.reduce((acc, i) => {
    const ms = new Date(i.json.isoDate || i.json.pubDate || 0).getTime();
    return ms > acc ? ms : acc;
  }, 0);
  staticData.lastRunAt = newestMs > 0 ? new Date(newestMs).toISOString() : new Date().toISOString();
}

// Format Google Doc append text
const google_doc_text = filtered.length > 0
  ? filtered.map(f =>
      `\n---\n**${f.title}**\nPublished: ${f.published}\nLink: ${f.link}\nKeywords: ${f.keywords.join(', ')}\n\n${f.summary}`
    ).join('\n')
  : '';

return [{
  json: {
    filtered_items:  filtered,
    filtered_count:  filtered.length,
    google_doc_text,
    run_at:          new Date().toISOString(),
  }
}];

const res  = $input.first().json;
const ok   = res.ok === true;
const count = res.stored || 0;

if (!ok) {
  throw new Error(`Pi-CEO workspace-intel POST failed: ${JSON.stringify(res)}`);
}

console.log(`✅ Workspace intel stored: ${count} item(s) at ${new Date().toISOString()}`);
return [{ json: { success: true, stored: count } }];
